class DefaultAppHandler {
    static var shared = DefaultAppHandler()
    
    func handle(url: URL) {
        guard let rootViewController = UIWindow.shared?.rootViewController else { return }
        guard let urlComponents = url.pathComponents else { return }

        switch urlComponents[1] {
        case "profile":
            if let id = urlComponents[2], let vc = ProfileViewController.newInstance(id: id) {
                rootViewController.navigationController?.pushViewController(vc, animated: true)
            } else {
                print("Invalid profile link")
            }
        case "payment/confirm":
            if let vc = PaymentConfirmViewController.newInstance() {
                rootViewController.present(vc, animated: true, completion: nil)
            } else {
                print("Failed to create payment confirm view controller")
            }
        default:
            // Handle unknown URLs
            let link = "\(url.scheme ?? "")://\(url.host ?? "").\(String(urlComponents.joined(separator: "/")))
            print("Unknown link \(link)")
        }
    }

    func open(url: URL) {
        guard UIApplication.shared.supportsOpeningURL(url) else { return }
        
        if let appUrl = url, let appBundleId = Bundle.main.infoDictionary?["CFBundleIdentifier"] as? String,
           let handlerType = HandlerType(rawValue: appBundleId),
           let handler = AppHandlerFactory.handler(type: handlerType) {
            handler.handle(url: appUrl)
        } else {
            if #available(iOS 14.0, *) {
                var info = [UIApplication.OpenExternalURLOptionsKey: UIApplication.OpenExternalURLOptionsValue]
                if url.scheme == "https" || url.scheme == "http" {
                    info[UIApplication.OpenExternalURLOptionsKey.isPreferedURType] = .preferenceAppURType
                }
                let canOpen = UIApplication.shared.open(url, options: info)
            } else {
                let canOpen = UIApplication.shared.open(url)
            }
